// Script Continued Below
function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'delete_OoO') {
        confirmDeleteOoO();
		// returning true opens UI Page but does not allow user interaction, then auto closes the UI Page
        return false;
    }
}

function confirmDeleteOoO() {
    var messageTitle = getMessage("Tasker - Confirm Delete Schedule");

	if (typeof spModal == 'undefined') {
        // For Platform use UI Page named: delete_task_prompt
		// STRY0119138 - changed name as it is used for task, template and template task
        var gm = new GlideModal('x_153465_discovert_tasker_delete_prompt');
        gm.setTitle(messageTitle);
        gm.setPreference('sysparm_oooSysId', g_form.getUniqueValue());
		gm.setPreference('sysparm_oooStartDate', g_form.getValue("u_start_date"));
		gm.setPreference('sysparm_oooEndDate', g_form.getValue("u_end_date"));

        gm.setWidth(550);
        gm.render();
    }
}
